INSERT INTO game_quest_skill_catalog (code, name, quest_title, category, skill_type, description, wuxing, power_percent, mp_cost, cooldown, max_level, level_up_bonus, additional_effect, special_mechanic, learn_cost, prerequisites, npc_id, target_type, scale_stat, rarity, pet_learnable, player_learnable, icon_url, sort_order, created_at, updated_at) VALUES
('P01', '連擊', '碎影雙刃・連環之路', 'physical', 'attack', '對敵方單體發動連續攻擊，隨機攻擊2~5次，每次造成55%ATK傷害。每次攻擊獨立判定目標，可能打到場上不同敵人。', '金', 55, 15, 2, 10, 5, NULL, '{"hitCount":[2,5],"multiTargetHit":true,"aoe":"single","aoeDescription":"單體（多段隨機目標）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'common', 1, 1, NULL, 101, 1774744854767, 1774744854767),
('P02', '諸刃', '斷鋼裂甲・諸刃之道', 'physical', 'attack', '集中全力的單體強力一擊，造成180%ATK傷害。高等級時傷害極為可觀。', '金', 180, 20, 3, 10, 12, NULL, '{"aoe":"single","aoeDescription":"單體"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'rare', 1, 1, NULL, 102, 1774744854767, 1774744854767),
('P03', '反擊', '以牙還牙・反擊之心', 'physical', 'passive', '被動技能。被物理攻擊時有機率自動反擊，造成100%ATK傷害。觸發機率隨等級提升（每級+5%）。', '金', 100, 0, 0, 10, 0, NULL, '{"isPassive":true,"passiveType":"counter","passiveTriggerChance":5,"passiveChancePerLevel":5,"aoe":"self","aoeDescription":"被動（自身）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'self', 'atk', 'rare', 1, 1, NULL, 103, 1774744854767, 1774744854767),
('P04', '崩擊', '山崩地裂・崩擊之力', 'physical', 'attack', '以沉重一擊砸向敵人，造成250%ATK傷害，並100%降低目標防禦30%，持續3回合。', '土', 250, 18, 4, 10, 15, '{"type":"defDown","chance":100,"value":30,"duration":3,"stackable":false}', '{"aoe":"single","aoeDescription":"單體"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'epic', 1, 1, NULL, 104, 1774744854767, 1774744854767),
('P05', '亂射', '萬箭齊發・亂射之術', 'physical', 'attack', '向敵方全體發射箭矢，對所有敵人造成80%ATK傷害。', '木', 80, 22, 4, 10, 6, NULL, '{"aoe":"all_enemy","aoeDescription":"敵方全體"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'all_enemy', 'atk', 'rare', 1, 1, NULL, 105, 1774744854767, 1774744854767),
('P06', '乾坤一擲', '孤注一擲・乾坤之賭', 'physical', 'attack', '傾注全力的致命一擊，造成350%ATK傷害，但命中率降低40%。高風險高回報的賭博型技能。', '火', 350, 25, 5, 10, 20, NULL, '{"accuracyMod":-40,"aoe":"single","aoeDescription":"單體"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'legendary', 1, 1, NULL, 106, 1774744854767, 1774744854767),
('P07', '迅速果斷', '疾風迅雷・果斷之刃', 'physical', 'attack', '先制攻擊，無視速度順序最先行動，且無視護盾直接造成150%ATK傷害。', '金', 150, 12, 3, 10, 8, NULL, '{"priority":true,"ignoreShield":true,"aoe":"single","aoeDescription":"單體（先制）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'rare', 1, 1, NULL, 107, 1774744854767, 1774744854767),
('P08', '毒擊', '蝕骨噬魂・毒擊之技', 'physical', 'attack', '帶有劇毒的攻擊，造成100%ATK傷害，80%機率使目標中毒5回合（每回合損失10%ATK的HP）。', '木', 100, 12, 2, 10, 5, '{"type":"poison","chance":80,"value":10,"duration":5,"stackable":false}', '{"aoe":"single","aoeDescription":"單體"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'common', 1, 1, NULL, 108, 1774744854767, 1774744854767),
('P09', '氣功彈', '內勁外放・氣功之道', 'physical', 'attack', '將內力凝聚為氣彈射出，造成130%ATK傷害，無視目標30%防禦。遠程物理攻擊。', '火', 130, 16, 2, 10, 8, NULL, '{"ignoreDefPercent":30,"aoe":"single","aoeDescription":"單體（遠程）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'common', 1, 1, NULL, 109, 1774744854767, 1774744854767),
('P10', '吸血攻擊', '血族之吻・吸血之爪', 'physical', 'attack', '帶有吸血效果的攻擊，造成120%ATK傷害，並將造成傷害的30%回復為自身HP。', '水', 120, 18, 3, 10, 8, NULL, '{"lifesteal":30,"aoe":"single","aoeDescription":"單體"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'rare', 1, 1, NULL, 110, 1774744854767, 1774744854767);
